module spi_memory_interface (
    input  wire        clk,           // System clock
    input  wire        spi_rst_n,       // Reset
    input  wire        st,            // Store (write) signal
    input  wire        ld,            // Load (read) signal
    input  wire [15:0] addr,          // 16-bit memory address
    input  wire [15:0] data_in,       // 16-bit data input (for write)
    output reg  [15:0] data_out,      // 16-bit data output (for read)
    input  wire        is_continous,  // Continuous transaction flag
    output reg         spi_cs,        // SPI Chip Select (Active Low)
    output reg         spi_clk,       // SPI Clock
    output reg         busy,          // Busy signal
    output reg         spi_mosi,      // SPI MOSI (Master Out Slave In)
    input  wire        spi_miso      // SPI MISO (Master In Slave Out)

  );

  // Define FSM states

  localparam  IDLE = 4'b0000;
  localparam  START = 4'b0001;
  localparam  SEND_CMD = 4'b0010;
  localparam  SEND_ADDR = 4'b0011;
  localparam  WRITE_DATA = 4'b0100;
  localparam  READ_DATA = 4'b0101;
  localparam  STOP = 4'b0110;
  localparam  TOGGLECLKON = 4'b0111;
  localparam  decideFate = 4'b1000;

  localparam  STcom = 1;
  localparam  LDcom = 0;


  reg[4:0] state;
  reg[4:0] last_state;
  reg command;

  reg [7:0] shift_reg; // Shift register for SPI data
  reg [5:0] bit_cnt;   // Bit counter
  reg [2:0] byte_cnt;  // Byte counter
  reg [15:0] recv_data;// Temporary storage for received data

  reg [0:0] prev_command;
  reg [15:0] prev_addr;
  reg prev_is_continous;

  always @(posedge clk , negedge spi_rst_n)
  begin

    if (!spi_rst_n)
    begin
      state   <= IDLE;
      spi_cs  <= 1'b1;
      spi_clk <= 1'b0;
      spi_mosi <= 1'b0;
      busy    <= 1'b0;
      bit_cnt <= 3'b000;
      byte_cnt <= 3'b000;
      command <= STcom;
      state <= IDLE;
      last_state <= IDLE;
    end
    else
    begin
      case (state)
        IDLE:
        begin
          busy <= 1'b0;
          if (st || ld)
          begin
            state <= START;
            busy <= 1'b1;

            prev_command <= command;
            prev_addr <= addr;
            prev_is_continous <= is_continous;

            if (st)
            begin
              shift_reg <= 8'h02; // Write command
              command <= STcom;
            end

            else if (ld)
            begin
              shift_reg <= 8'h03; // Read command
              command <= LDcom;
            end

          end
        end

        START:
        begin
          spi_cs <=1'b0;
          bit_cnt <= 3'b000;
          byte_cnt <= 3'b000;
          state <= SEND_CMD;
        end

        SEND_CMD:
        begin
          spi_clk <= 0;
          if (bit_cnt < 8)
          begin
            spi_mosi <= shift_reg[7];  // Send MSB first
            shift_reg <= shift_reg << 1; // Shift left
            last_state <= state;

            state <= TOGGLECLKON;
            bit_cnt <= bit_cnt + 1;
          end
          else
          begin
            state <= SEND_ADDR;
            shift_reg <= addr[15:8]; // Load high byte of address
            bit_cnt <= 0;
          end
        end

        SEND_ADDR:
        begin

          spi_clk <= 0;
          if (bit_cnt < 8)
          begin
            spi_mosi <= shift_reg[7];
            shift_reg <= shift_reg << 1;
            spi_clk <= 0;
            last_state <= state;
            state <= TOGGLECLKON;
            bit_cnt <= bit_cnt + 1;
          end
          else if (byte_cnt == 0)
          begin
            shift_reg <= addr[7:0]; // Load low byte of addresscc
            byte_cnt <= 1;
            bit_cnt <= 0;
          end
          else
          begin
            state <= command ? WRITE_DATA : READ_DATA;
            shift_reg <= command ? data_in[15:8] : 8'h00; // Load high data or dummy
            recv_data[15:0] <= 16'h0000; // Clear received data
            bit_cnt <= 0;
            byte_cnt <= 0;
            spi_mosi <= 1'b0;
          end
        end

        WRITE_DATA:
        begin

          spi_clk <= 0;
          if (bit_cnt < 8)
          begin
            spi_mosi <= shift_reg[7];
            shift_reg <= shift_reg << 1;

            last_state <= state;
            state <= TOGGLECLKON;
            bit_cnt <= bit_cnt + 1;
          end
          else if (byte_cnt == 0)
          begin
            shift_reg <= data_in[7:0]; // Load low byte
            byte_cnt <= 1;
            bit_cnt <= 0;
          end
          else
          begin
            state <= decideFate; // Decide next state based on command
          end
        end

        READ_DATA:
        begin

          spi_clk <= 0;
          if (bit_cnt < 17)
          begin
            last_state<=state;

            if (bit_cnt<16)
              state <= TOGGLECLKON;
            bit_cnt <= bit_cnt + 1;
            recv_data[15:0] <= {recv_data[14:0], spi_miso}; // Shift left


          end
          else
          begin
            recv_data[15:0] <= {recv_data[14:0], spi_miso};
            data_out <= recv_data;
            state <= decideFate; // Decide next state based on command
            bit_cnt <= 0;
          end
        end


        STOP:
        begin

          spi_clk <= 0;
          spi_cs <= 1'b1;
          busy <= 1'b0;
          state <= IDLE;
        end

        TOGGLECLKON:
        begin
          spi_clk <= 1;
          state <= last_state;
        end

        decideFate:
        begin
          if (command == prev_command &&
              addr == prev_addr + 1 &&
              is_continous == prev_is_continous)
          begin
            // Continue without releasing CS
            shift_reg <= command ? data_in[15:8] : 8'h00;
            bit_cnt <= 0;
            byte_cnt <= 0;
            recv_data <= 0;
            spi_mosi <= 0;
            state <= command ? WRITE_DATA : READ_DATA;

            // Update previous address
            prev_addr <= addr;
          end
          else
          begin
            // End transaction
            state <= STOP;
          end
        end
        default :
          state <= STOP;

      endcase
    end

  end

endmodule

module cpu_cycle_controller
  (
    input  wire clk,
    input  wire rst_n,

    input  wire fetch_done,
    input  wire data_done,

    input  wire ld,
    input  wire st,

    output wire fetch_req,
    output wire execute_now_pulse
  );

  localparam S_REQ_FETCH  = 2'd0;
  localparam S_WAIT_FETCH = 2'd1;
  localparam S_EXECUTE    = 2'd2;
  localparam S_WAIT_DATA  = 2'd3;

  reg [1:0] state;

  wire execute_now;
  assign execute_now = (state == S_EXECUTE);
  assign fetch_req   = (state == S_REQ_FETCH);

  always @(posedge clk , negedge rst_n)
  begin
    if (!rst_n)
    begin
      state <= S_REQ_FETCH;
    end
    else
    begin
      case (state)
        S_REQ_FETCH:
          state <= S_WAIT_FETCH;

        S_WAIT_FETCH:
        begin
          if (fetch_done)
            state <= S_EXECUTE;
        end

        S_EXECUTE:
        begin
          if (ld || st)
            state <= S_WAIT_DATA;
          else
            state <= S_REQ_FETCH;
        end

        S_WAIT_DATA:
        begin
          if (data_done)
            state <= S_REQ_FETCH;
        end

        default:
          state <= S_REQ_FETCH;
      endcase
    end
  end

  // rise detector
  reg sig_d;
  always @(posedge clk, negedge rst_n)
  begin
    if (!rst_n)
      sig_d <= 1'b0;
    else
      sig_d <= execute_now;
  end

  assign execute_now_pulse = execute_now & ~sig_d;
endmodule

module interrupt_controller_small (
    input  [3:0] dOut,
    input  [15:0] Addr,
    input         ioW,
    input         ioR,
    input         C,
    input         rst_n,

    input  [3:0]  irq_in,
    input         imm,
    input         reti,
    input         pc_en,

    input  [15:0] CPUInterruptEnableAddr,
    input  [15:0] inputInterruptAddr,
    input  [15:0] interruptRegAddr,

    output [15:0] InterruptOut,
    output        intr,
    output        irq_lock
);

  reg       global_enable;
  reg       irq_lock_r   ;
  reg [3:0] irq_enable   ;
  reg [3:0] irq_pending  ;

  wire wr_ctrl;
  wire wr_enable;
  wire wr_pending;

  wire rd_ctrl;
  wire rd_enable;
  wire rd_pending;

  wire [3:0] pending_with_new_irq;
  wire [3:0] active_irq;
  wire       intr_take;

  assign wr_ctrl    = ioW && (Addr == CPUInterruptEnableAddr);
  assign wr_enable  = ioW && (Addr == inputInterruptAddr);
  assign wr_pending = ioW && (Addr == interruptRegAddr);

  assign rd_ctrl    = ioR && (Addr == CPUInterruptEnableAddr);
  assign rd_enable  = ioR && (Addr == inputInterruptAddr);
  assign rd_pending = ioR && (Addr == interruptRegAddr);

  assign pending_with_new_irq = irq_pending | irq_in;
  assign active_irq           = irq_pending & irq_enable;

  assign intr      = global_enable && !irq_lock_r && !imm && (active_irq != 4'b0000);
  assign irq_lock  = irq_lock_r;
  assign intr_take = intr && pc_en;

  always @(posedge C or negedge rst_n)
  begin
    if (!rst_n)
    begin
      global_enable <= 1'b0;
      irq_lock_r    <= 1'b0;
      irq_enable    <= 4'b0000;
      irq_pending   <= 4'b0000;
    end
    else
    begin
      // default: latch new interrupt requests
      irq_pending <= pending_with_new_irq;

      // global interrupt enable
      if (wr_ctrl)
        global_enable <= dOut[0];

      // source enable bits [3:0]
      if (wr_enable)
        irq_enable <= dOut[3:0];

      // write 1 to clear pending bits
      if (wr_pending)
        irq_pending <= pending_with_new_irq & ~dOut[3:0];

      // lock once interrupt is actually taken
      if (intr_take)
        irq_lock_r <= 1'b1;

      // unlock only on RETI
      if (reti)
        irq_lock_r <= 1'b0;
    end
  end

  assign InterruptOut =
      rd_ctrl    ? {13'h0000, intr, irq_lock_r, global_enable} :
      rd_enable  ? {12'h000, irq_enable} :
      rd_pending ? {12'h000, irq_pending} :
      16'h0000;

endmodule
module lfsr_RandomNumberGen (
    input  [15:0] adrrIn,
    input  [7:0] dataIn,
    input         ioW,
    input         clk,
    input         ioR,
    input  [15:0] SeedAdr,
    input  [15:0] RngAdr,
    output [15:0] Out
);

    reg [7:0] seed_reg;
    reg [7:0] lfsr    ;

    wire seed_wr  = ioW && (adrrIn == SeedAdr);
    wire seed_rd  = ioR && (adrrIn == SeedAdr);
    wire rng_rd   = ioR && (adrrIn == RngAdr);

    // 8-bit maximal-length taps
    // polynomial: x^8 + x^6 + x^5 + x^4 + 1
    wire feedback = lfsr[7] ^ lfsr[5] ^ lfsr[4] ^ lfsr[3];

    always @(posedge clk) begin
        if (seed_wr) begin
            seed_reg <= dataIn[7:0];
            lfsr <= (dataIn[7:0] == 8'h00) ? 8'h01 : dataIn[7:0];
        end else begin
            lfsr <= {lfsr[6:0], feedback};
        end
    end

    assign Out = seed_rd ? {8'h00, seed_reg} :
                 rng_rd  ? {8'h00, lfsr}     :
                           16'h0000;

endmodule
module timer (
    input  [15:0] dOut,
    input  [15:0] Addr,
    input         ioW,
    input         ioR,
    input         C,
    input         InterLock,
    input  [15:0] timerConfigAddr,
    input  [15:0] timerTargetAddr,
    input  [15:0] timerResetAddr,
    input  [15:0] timerReadAddr,
    input  [15:0] timerSyncStartAddr,
    input         rst_n,
    output [15:0] TimerOut,
    output        timer_interrupt
  );

