            default:
                out = 'h0;
        endcase
    end
endmodule

module i2c_master_ctrl (
    input              clk,
    input              rst_n,

    input              wr_en,
    input      [3:0]   reg_addr,
    input      [15:0]  cpu_din,
    output reg [15:0]  cpu_dout,

    input              sda_in,
    input              scl_in,
    output             sda_out,
    output             scl_out,
    output reg         sda_oe,
    output reg         scl_oe,

    output             interrupt
);

assign sda_out = 1'b0;
assign scl_out = 1'b0;
assign interrupt = irq_enable & irq_pending;

localparam ST_IDLE       = 4'd0;
localparam ST_START_1    = 4'd1;
localparam ST_START_2    = 4'd2;
localparam ST_START_3    = 4'd3;
localparam ST_BIT_SETUP  = 4'd4;
localparam ST_BIT_HIGH   = 4'd5;
localparam ST_BIT_LOW    = 4'd6;
localparam ST_ACK_SETUPW = 4'd7;
localparam ST_ACK_HIGHW  = 4'd8;
localparam ST_ACK_LOWW   = 4'd9;
localparam ST_ACK_SETUPR = 4'd10;
localparam ST_ACK_HIGHR  = 4'd11;
localparam ST_ACK_LOWR   = 4'd12;
localparam ST_STOP_1     = 4'd13;
localparam ST_STOP_2     = 4'd14;
localparam ST_STOP_3     = 4'd15;

reg        enable;
reg        irq_enable;
reg        stretch_enable;

reg        op_busy;
reg        bus_active;
reg        done;
reg        ack_error;
reg        rx_valid;
reg        irq_pending;

reg [15:0] prescale_reg;
reg [15:0] divcnt;
reg        sm_tick;

reg [7:0]  tx_data_reg;
reg [7:0]  rx_data_reg;

reg [7:0]  tx_shift;
reg [7:0]  rx_shift;
reg [3:0]  bit_count;

reg        cmd_start;
reg        cmd_stop;
reg        cmd_write;
reg        cmd_read;
reg        cmd_read_nack;

reg [3:0]  state;

wire launch_cmd;
assign launch_cmd = wr_en && (reg_addr == 4'h4) && !op_busy && enable &&
                    (cpu_din[0] || cpu_din[1] || cpu_din[2] || cpu_din[3]);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        enable         <= 1'b0;
        irq_enable     <= 1'b0;
        stretch_enable <= 1'b0;

        op_busy        <= 1'b0;
        bus_active     <= 1'b0;
        done           <= 1'b0;
        ack_error      <= 1'b0;
        rx_valid       <= 1'b0;
        irq_pending    <= 1'b0;

        prescale_reg   <= 16'd0;
        divcnt         <= 16'd0;
        sm_tick        <= 1'b0;

        tx_data_reg    <= 8'd0;
        rx_data_reg    <= 8'd0;
        tx_shift       <= 8'd0;
        rx_shift       <= 8'd0;
        bit_count      <= 4'd0;

        cmd_start      <= 1'b0;
        cmd_stop       <= 1'b0;
        cmd_write      <= 1'b0;
        cmd_read       <= 1'b0;
        cmd_read_nack  <= 1'b0;

        state          <= ST_IDLE;

        sda_oe         <= 1'b0;
        scl_oe         <= 1'b0;
    end else begin
        sm_tick <= 1'b0;

        if (op_busy) begin
            if (prescale_reg == 16'd0) begin
                sm_tick <= 1'b1;
            end else begin
                if (divcnt == 16'd0) begin
                    divcnt  <= prescale_reg;
                    sm_tick <= 1'b1;
                end else begin
                    divcnt <= divcnt - 16'd1;
                end
            end
        end else begin
            divcnt <= 16'd0;
        end

        if (wr_en) begin
            case (reg_addr)
                4'h0: begin
                    enable         <= cpu_din[0];
                    irq_enable     <= cpu_din[1];
                    stretch_enable <= cpu_din[2];
                end

                4'h1: begin
                    if (cpu_din[2]) done        <= 1'b0;
                    if (cpu_din[3]) ack_error   <= 1'b0;
                    if (cpu_din[4]) rx_valid    <= 1'b0;
                    if (cpu_din[5]) irq_pending <= 1'b0;
                end

                4'h2: begin
                    prescale_reg <= cpu_din;
                end

                4'h3: begin
                    tx_data_reg <= cpu_din[7:0];
                end
            endcase
        end

        if (launch_cmd) begin
            cmd_start     <= cpu_din[0];
            cmd_stop      <= cpu_din[1];
            cmd_write     <= cpu_din[2];
            cmd_read      <= cpu_din[3];
            cmd_read_nack <= cpu_din[4];

            done        <= 1'b0;
            ack_error   <= 1'b0;
            irq_pending <= 1'b0;

            tx_shift    <= tx_data_reg;
            rx_shift    <= 8'd0;
            bit_count   <= 4'd7;
            op_busy     <= 1'b1;

            if (cpu_din[0]) begin
                state  <= ST_START_1;
                sda_oe <= 1'b0;
                scl_oe <= 1'b0;
            end else if (cpu_din[2] || cpu_din[3]) begin
                state <= ST_BIT_SETUP;
                scl_oe <= 1'b1;
            end else if (cpu_din[1]) begin
                state  <= ST_STOP_1;
                sda_oe <= 1'b1;
                scl_oe <= 1'b1;
            end else begin
                op_busy <= 1'b0;
                done    <= 1'b1;
                irq_pending <= 1'b1;
                state   <= ST_IDLE;
            end
        end

        if (sm_tick && op_busy) begin
            case (state)
                ST_IDLE: begin
                    op_busy <= 1'b0;
                end

                ST_START_1: begin
                    sda_oe <= 1'b0;
                    scl_oe <= 1'b0;
                    if (sda_in && ((!stretch_enable) || scl_in)) begin
                        state <= ST_START_2;
                    end
                end

                ST_START_2: begin
                    sda_oe <= 1'b1; // SDA low while SCL high
                    scl_oe <= 1'b0;
                    state  <= ST_START_3;
                end

                ST_START_3: begin
                    scl_oe     <= 1'b1; // pull SCL low
                    bus_active <= 1'b1;

                    if (cmd_write || cmd_read) begin
                        state <= ST_BIT_SETUP;
                    end else if (cmd_stop) begin
                        state <= ST_STOP_1;
                    end else begin
                        done        <= 1'b1;
                        irq_pending <= 1'b1;
                        op_busy     <= 1'b0;
                        state       <= ST_IDLE;
                    end
                end

                ST_BIT_SETUP: begin
                    scl_oe <= 1'b1; // keep clock low during setup

                    if (cmd_write) begin
                        if (tx_shift[bit_count])
                            sda_oe <= 1'b0; // release for logic 1
                        else
                            sda_oe <= 1'b1; // drive low for logic 0
                    end else begin
                        sda_oe <= 1'b0; // read bit: release SDA
                    end

                    state <= ST_BIT_HIGH;
                end

                ST_BIT_HIGH: begin
                    scl_oe <= 1'b0; // release SCL high

                    if ((!stretch_enable) || scl_in) begin
                        if (cmd_read)
                            rx_shift[bit_count] <= sda_in;

                        state <= ST_BIT_LOW;
                    end
                end

                ST_BIT_LOW: begin
                    scl_oe <= 1'b1; // drive SCL low again

                    if (bit_count != 4'd0) begin
                        bit_count <= bit_count - 4'd1;
                        state     <= ST_BIT_SETUP;
                    end else begin
                        if (cmd_write)
                            state <= ST_ACK_SETUPW;
                        else
                            state <= ST_ACK_SETUPR;
                    end
                end

                ST_ACK_SETUPW: begin
                    sda_oe <= 1'b0; // slave drives ACK/NACK
                    scl_oe <= 1'b1;
                    state  <= ST_ACK_HIGHW;
                end

                ST_ACK_HIGHW: begin
                    scl_oe <= 1'b0;

                    if ((!stretch_enable) || scl_in) begin
                        if (sda_in)
                            ack_error <= 1'b1;

                        state <= ST_ACK_LOWW;
                    end
                end

                ST_ACK_LOWW: begin
                    scl_oe <= 1'b1;
                    sda_oe <= 1'b0;

                    if (cmd_stop) begin
                        state <= ST_STOP_1;
                    end else begin
                        done        <= 1'b1;
                        irq_pending <= 1'b1;
                        op_busy     <= 1'b0;
                        state       <= ST_IDLE;
                    end
                end

                ST_ACK_SETUPR: begin
                    scl_oe <= 1'b1;

                    if (cmd_read_nack)
                        sda_oe <= 1'b0; // NACK = release high
                    else
                        sda_oe <= 1'b1; // ACK = drive low

                    state <= ST_ACK_HIGHR;
                end

                ST_ACK_HIGHR: begin
                    scl_oe <= 1'b0;

                    if ((!stretch_enable) || scl_in) begin
                        state <= ST_ACK_LOWR;
                    end
                end

                ST_ACK_LOWR: begin
                    scl_oe      <= 1'b1;
                    sda_oe      <= 1'b0;
                    rx_data_reg <= rx_shift;
                    rx_valid    <= 1'b1;

                    if (cmd_stop) begin
                        state <= ST_STOP_1;
                    end else begin
                        done        <= 1'b1;
                        irq_pending <= 1'b1;
                        op_busy     <= 1'b0;
                        state       <= ST_IDLE;
                    end
                end

                ST_STOP_1: begin
                    sda_oe <= 1'b1; // SDA low
                    scl_oe <= 1'b1; // SCL low
                    state  <= ST_STOP_2;
                end

                ST_STOP_2: begin
                    sda_oe <= 1'b1; // keep SDA low
                    scl_oe <= 1'b0; // release SCL high

                    if ((!stretch_enable) || scl_in) begin
                        state <= ST_STOP_3;
                    end
                end

                ST_STOP_3: begin
                    sda_oe      <= 1'b0; // release SDA high
                    scl_oe      <= 1'b0;
                    bus_active  <= 1'b0;
                    done        <= 1'b1;
                    irq_pending <= 1'b1;
                    op_busy     <= 1'b0;
                    state       <= ST_IDLE;
                end

                default: begin
                    sda_oe      <= 1'b0;
                    scl_oe      <= 1'b0;
                    bus_active  <= 1'b0;
                    done        <= 1'b1;
                    ack_error   <= 1'b1;
                    irq_pending <= 1'b1;
                    op_busy     <= 1'b0;
                    state       <= ST_IDLE;
                end
            endcase
        end
    end
end

always @(*) begin
    cpu_dout = 16'd0;

    case (reg_addr)
        4'h0: begin
            cpu_dout[0] = enable;
            cpu_dout[1] = irq_enable;
            cpu_dout[2] = stretch_enable;
        end

        4'h1: begin
            cpu_dout[0] = op_busy;
            cpu_dout[1] = bus_active;
            cpu_dout[2] = done;
            cpu_dout[3] = ack_error;
            cpu_dout[4] = rx_valid;
            cpu_dout[5] = irq_pending;
        end

        4'h2: begin
            cpu_dout = prescale_reg;
        end

        4'h3: begin
            cpu_dout[7:0] = rx_data_reg;
        end

        4'h4: begin
            cpu_dout[0] = cmd_start;
            cpu_dout[1] = cmd_stop;
            cpu_dout[2] = cmd_write;
            cpu_dout[3] = cmd_read;
            cpu_dout[4] = cmd_read_nack;
        end

        default: begin
            cpu_dout = 16'd0;
        end
    endcase
end

endmodule
module is_different (
    input  [15:0] in1,
    input  [15:0] in2,

    output        different
  );
  assign different = (in1 != in2);

endmodule


module singExtend (
  input [7:0] inst,
  output [15:0] \4S , // The four bits taken from Rs.
  output [15:0] \8SD , // The eight bits taken from Rs,Rd with sign extension.
  output [15:0] \4D  // The four bits taken from Rd.

);
  wire s0;
  assign \4D [3:0] = inst[7:4];
  assign \4D [15:4] = 12'b0;
  assign \4S [3:0] = inst[3:0];
  assign \4S [15:4] = 12'b0;
  assign s0 = inst[7];
  assign \8SD [6:0] = inst[6:0];
  assign \8SD [7] = s0;
  assign \8SD [8] = s0;
  assign \8SD [9] = s0;
  assign \8SD [10] = s0;
  assign \8SD [11] = s0;
  assign \8SD [12] = s0;
  assign \8SD [13] = s0;
  assign \8SD [14] = s0;
  assign \8SD [15] = s0;
endmodule
module opcode_microcode_rom(
    input  [6:0] opcode,
    output muxb0,
    output muxb1,
    output muxb2,
    output aluop0,
    output aluop1,
    output aluop2,
    output aluop3,
    output aluop4,
    output aluop5,
    output WE,
    output sf,
    output iem0,
    output iem1,
    output br0,
    output br1,
    output br2,
    output muxA,
    output ld,
    output st,
    output abs,
    output ioW,
    output ioR,
    output stPC,
    output Reti
);

reg [23:0] ctrl;

assign {
    muxb0,
    muxb1,
    muxb2,
    aluop0,
    aluop1,
    aluop2,
    aluop3,
    aluop4,
    aluop5,
    WE,
    sf,
    iem0,
    iem1,
    br0,
    br1,
    br2,
    muxA,
    ld,
    st,
    abs,
    ioW,
    ioR,
    stPC,
    Reti
} = ctrl;

always @(*) begin
    case (opcode)
        7'b0000000: ctrl = 24'b0000_0000_0000_0000_0000_0000;//8'hx00:
        7'b0000001: ctrl = 24'b0000_0000_0100_0000_1000_0000;//8'hx01:
        7'b0000010: ctrl = 24'b0000_0000_1110_0000_0000_0000;//8'hx02:
        7'b0000011: ctrl = 24'b0001_0000_1110_0000_0000_0000;//8'hx03:
        7'b0000100: ctrl = 24'b0000_0001_0110_0000_0000_0000;//8'hx04:
        7'b0000101: ctrl = 24'b0001_0001_0110_0000_0000_0000;//8'hx05:
        7'b0000110: ctrl = 24'b0000_0001_1110_0000_0000_0000;//8'hx06:
        7'b0000111: ctrl = 24'b0000_0010_0110_0000_0000_0000;//8'hx07:
        7'b0001000: ctrl = 24'b0000_0010_1110_0000_0000_0000;//8'hx08:
        7'b0001001: ctrl = 24'b0100_0000_0101_0000_0000_0000;//8'hx09:
        7'b0001010: ctrl = 24'b1010_0000_0100_0000_0000_0000;//8'hx0A:
        7'b0001011: ctrl = 24'b0100_0000_1111_0000_0000_0000;//8'hx0B:
        7'b0001100: ctrl = 24'b1010_0000_1110_0000_0000_0000;//8'hx0C:
        7'b0001101: ctrl = 24'b0101_0000_1111_0000_0000_0000;//8'hx0D:
        7'b0001110: ctrl = 24'b1011_0000_1110_0000_0000_0000;//8'hx0E:
        7'b0001111: ctrl = 24'b0100_0001_0111_0000_0000_0000;//8'hx0F:
        7'b0010000: ctrl = 24'b1010_0001_0110_0000_0000_0000;//8'hx10:
        7'b0010001: ctrl = 24'b0101_0001_0111_0000_0000_0000;//8'hx11:
        7'b0010010: ctrl = 24'b1011_0001_0110_0000_0000_0000;//8'hx12:
        7'b0010011: ctrl = 24'b0000_0011_1100_0000_0000_0000;//8'hx13:
        7'b0010100: ctrl = 24'b0100_0001_1111_0000_0000_0000;//8'hx14:
